import classes from "./Layout.module.css";

const Layout = (props) => {
  return (
    <div className={classes["container"]}>
      <nav className={classes["nav-wrapper"]}>
        {props.nav}
      </nav>

      <div className={classes["base"]}>
        {props.sidebar}
        {props.children}
      </div>
    </div>
  );
};

export default Layout;
